// pubspec: provider: ^6.1.2
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';

// 1. The model ÔÇö plain Dart class extending ChangeNotifier
class CartModel extends ChangeNotifier {
  final _items = <String>[];
  List<String> get items => List.unmodifiable(_items);
  int get count => _items.length;

  void add(String item) { _items.add(item); notifyListeners(); }
  void clear() { _items.clear(); notifyListeners(); }
}

// 2. Provide near the top of the tree
void main() {
  runApp(
    ChangeNotifierProvider(
      create: (_) => CartModel(),
      child: const MaterialApp(home: HomePage()),
    ),
  );
}

// 3. Consume ÔÇö three flavors
class HomePage extends StatelessWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Cart demo')),
    body: Column(
      children: [
        // (a) context.watch<T>() ÔÇö read + subscribe (rebuilds on notify)
        Text('Items: ${context.watch<CartModel>().count}'),

        // (b) Consumer<T> ÔÇö surgical: only this subtree rebuilds
        Consumer<CartModel>(
          builder: (context, cart, child) => Expanded(
            child: ListView(children: cart.items.map((s) => Text(s)).toList()),
          ),
        ),

        // (c) context.read<T>() ÔÇö read WITHOUT subscribing (use in callbacks)
        FilledButton(
          onPressed: () => context.read<CartModel>().add('apple'),
          child: const Text('Add apple'),
        ),
      ],
    ),
  );
}

// Consumer rebuilds on ANY notifyListeners() from CartModel.
// If you only care about `count`, use Selector so the widget rebuilds
// ONLY when the extracted value changes.

Selector<CartModel, int>(
  selector: (context, cart) => cart.count,
  builder: (context, count, child) => Text('Items: $count'),
)

// Now this Text rebuilds only when `count` changes ÔÇö even if CartModel
// notifies for reasons that don't affect count (e.g., a sort-order change).
// This is the direct equivalent of Riverpod's `ref.watch(p.select((s) => s.count))`.
